import os
from vex_sdk import VexClient

vex = VexClient(api_key=os.getenv('VEX_API_KEY'))

def validate_bing_grounding(search_results: dict, max_age_days: int = 30):
    for result in search_results['webPages']:
        verdict = vex.validate_content({
            'content': result['snippet'],
            'metadata': {'publish_date': result.get('date')},
            'policy': 'insurance-data-freshness',
            'max_age_days': max_age_days
        })
        if not verdict.passed:
            return {'blocked': True, 'reason': 'Outdated grounding data'}
    return {'approved': True}

import { VexClient } from '@vex/sdk';

const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });

export async function safeFileSearch(
  projectId: string,
  query: string,
  files: any[]
): Promise<any> {
  const results = await azureClient.files.search(projectId, query);

  for (const file of results) {
    const verdict = await vex.validateContent({
      content: file.content,
      metadata: { azure_metadata: true },
      policy: 'insurance-pii-redaction',
      domain: 'claims-processing'
    });

    if (!verdict.passed) {
      file.content = '[REDACTED - PII DETECTED]';
      file.vex_blocked = verdict.violations;
    }
  }

  return results;
}
